from Bio import pairwise2

QUERY = ""

HER2 = ""

print("Query length:", len(QUERY))
print("HER2 P04626 (partial, fetched 2026-03-29) length:", len(HER2))
print()

# Check if any 10-mer from query appears in HER2
print("=== 10-mer exact match scan ===")
hits = []
for i in range(0, len(QUERY)-10, 10):
    kmer = QUERY[i:i+10]
    pos = HER2.find(kmer)
    if pos >= 0:
        hits.append((i, pos, kmer))
print("Exact 10-mer hits in P04626:", len(hits))
for h in hits[:5]:
    print("  Query[%d]: %s  -> P04626[%d]" % (h[0], h[2], h[1]))

print()

# Local alignment (fast: Smith-Waterman, only match score)
alns = pairwise2.align.localms(QUERY, HER2, 2, -1, -5, -0.5, one_alignment_only=True)
if alns:
    a = alns[0]
    q_aln = a.seqA
    h_aln = a.seqB
    aligned_len = sum(1 for q, h in zip(q_aln, h_aln) if q != '-' and h != '-')
    identities = sum(1 for q, h in zip(q_aln, h_aln) if q == h and q != '-')
    pct_id = 100.0 * identities / aligned_len if aligned_len > 0 else 0
    pct_cov = 100.0 * aligned_len / len(QUERY)
    print("=== Best local alignment (Smith-Waterman) ===")
    print("Score:", a.score)
    print("Aligned length:", aligned_len, "/ query length:", len(QUERY))
    print("Identities: %d / %d" % (identities, aligned_len))
    print("Identity: %.1f%%" % pct_id)
    print("Query coverage: %.1f%%" % pct_cov)
    print()
    print("Query  :", q_aln[:80])
    print("HER2   :", h_aln[:80])
else:
    print("No alignment found — sequences are unrelated")
